code.Java:
class Solution {
    public int heightOfBinaryTree(Node root) {
        return Math.max(0, depth(root) - 1);
    }

    public int depth(Node root) {
        if (root == null) return 0;
        int left = depth(root.left);
        int right = depth(root.right);
        return Math.max(left, right) + 1;
    }
}

